# Core module defining interfaces and abstract base classes
from data import DataPacket

interface IPlugin:
    def get_name(self) -> str:
        ...

    def process(self, data: DataPacket) -> int:
        ...

class PluginBase:
    _name: str
    enabled: bool

    def __init__(self, name: str):
        self._name = name
        self.enabled = True

    property get name(self) -> str:
        return self._name

    @virtual
    def prepare(self) -> bool:
        return self.enabled

class PluginManager[T: IPlugin]:
    _plugins: list[T]

    def __init__(self):
        self._plugins = []

    def register(self, plugin: T) -> None:
        self._plugins.append(plugin)

    def process_all(self, data: DataPacket) -> int:
        total: int = 0
        for plugin in self._plugins:
            if plugin.prepare():
                total += plugin.process(data)
        return total

