# Plugins module implementing core interfaces
from core import PluginBase, IPlugin
from data import DataPacket, DataType, Priority

class TextProcessor(PluginBase, IPlugin):
    _priority: Priority

    def __init__(self, priority: Priority):
        super().__init__("TextProcessor")
        self._priority = priority

    def get_name(self) -> str:
        return self._name

    def process(self, data: DataPacket) -> int:
        if data.data_type == DataType.TEXT:
            return data.payload * self._priority.value
        return 0

class NumberProcessor(PluginBase, IPlugin):
    _offset: int

    def __init__(self, offset: int):
        super().__init__("NumberProcessor")
        self._offset = offset

    def get_name(self) -> str:
        return self._name

    def process(self, data: DataPacket) -> int:
        if data.data_type == DataType.NUMBER:
            return data.payload + self._offset
        return 0

    @override
    def prepare(self) -> bool:
        return super().prepare() and self._offset > 0

class BinaryProcessor(PluginBase, IPlugin):
    def __init__(self):
        super().__init__("BinaryProcessor")

    def get_name(self) -> str:
        return self._name

    def process(self, data: DataPacket) -> int:
        if data.data_type == DataType.BINARY:
            return data.payload // 2
        return 0

def create_packet(dt: DataType, payload: int, tag: str) -> DataPacket:
    return DataPacket(dt, payload, tag)
